import { Injectable } from '@angular/core';
import { HttpClient, HttpParams } from '@angular/common/http';
import { Observable } from 'rxjs';

export interface ExpenseItem {
  id?: string;
  date: string;
  category: string;
  amount: number;
  description?: string;
}

@Injectable({
  providedIn: 'root'
})
export class ExpensesService {
  private apiUrl = 'http://localhost:3000/api/expenses';

  constructor(private http: HttpClient) {}

  getAllExpenses(): Observable<ExpenseItem[]> {
    return this.http.get<ExpenseItem[]>(this.apiUrl);
  }

  getExpenseById(id: string): Observable<ExpenseItem> {
    return this.http.get<ExpenseItem>(`${this.apiUrl}/${id}`);
  }

  getExpensesWithLimit(limit: number): Observable<ExpenseItem[]> {
    const params = new HttpParams().set('limit', limit.toString());
    return this.http.get<ExpenseItem[]>(this.apiUrl, { params });
  }

  createExpense(expense: Omit<ExpenseItem, 'id'>): Observable<ExpenseItem> {
    return this.http.post<ExpenseItem>(this.apiUrl, expense);
  }

  updateExpense(id: string, expense: Partial<ExpenseItem>): Observable<ExpenseItem> {
    return this.http.put<ExpenseItem>(`${this.apiUrl}/${id}`, expense);
  }

  deleteExpense(id: string): Observable<void> {
    return this.http.delete<void>(`${this.apiUrl}/${id}`);
  }
}
